Location: crates/dsrs-macros/src/lib.rs

Supported field-level syntax:
```rust
#[derive(Signature)]
struct MySig {
    #[input]
    #[render(style = "json")]
    context: Vec<Document>,

    #[input]
    #[render(template = r#"- {{ value.title }}"#)]
    note: NoteData,

    #[input]
    #[render(fn = "crate::render_note")]
    detailed_note: NoteData,

    #[input]
    #[render(max_list_items = 5, max_string_chars = 1000)]
    history: REPLHistory,
}
```

